def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_time = float('inf')
    best_node = 0
    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        time_to_customer = distance_to_customer + np.linalg.norm(depot_pos - customer_pos)
        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                waiting_time = np.linalg.norm(customer_pos - other_truck_pos)
                arrival_time = time_to_customer + np.maximum(waiting_time, 0)
                if arrival_time < min_time:
                    min_time = arrival_time
                    best_node = i
    return best_node
